{
  "name": "FocusAR: ADHD Memory Offload",
  "description": "A futuristic AR heads-up display designed to help ADHD users offload distracting thoughts instantly. Features real-time voice capture, facial expression stress detection, and a 'Presence Guide' to reduce interruption habits.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

export interface Thought {
  id: string;
  content: string;
  timestamp: number;
  tags: string[];
  priority: 'low' | 'medium' | 'high';
}

export enum AppState {
  IDLE = 'IDLE',
  LISTENING = 'LISTENING',
  SAVING = 'SAVING',
  CONFIRMED = 'CONFIRMED',
  STRESSED = 'STRESSED'
}

export interface UserStats {
  thoughtsOffloaded: number;
  presenceTime: number; // in minutes
  anxietyEvents: number;
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeThought = async (text: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze this fleeting thought from an ADHD user. Summarize it briefly and categorize it. 
    Thought: "${text}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          category: { type: Type.STRING },
          priority: { type: Type.STRING, enum: ['low', 'medium', 'high'] }
        },
        required: ['summary', 'category', 'priority']
      }
    }
  });

  return JSON.parse(response.text);
};

export const detectStressFromFrame = async (base64Image: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          inlineData: {
            mimeType: 'image/jpeg',
            data: base64Image
          }
        },
        { text: "Analyze the person's facial expression. Are they showing signs of anxiety, intense hyper-focus, or cognitive overload (fidgeting, furrowed brow)? Respond only with a boolean 'true' or 'false' for high stress." }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            isStressed: { type: Type.BOOLEAN },
            detectedEmotion: { type: Type.STRING }
          },
          required: ['isStressed']
        }
      }
    });
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Stress detection failed", e);
    return { isStressed: false, detectedEmotion: 'neutral' };
  }
};

import React, { useEffect, useRef } from 'react';

interface CameraHUDProps {
  onFrame: (base64: string) => void;
  isActive: boolean;
}

const CameraHUD: React.FC<CameraHUDProps> = ({ onFrame, isActive }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    async function startCamera() {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: 1280, height: 720 },
          audio: false 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
      } catch (err) {
        console.error("Error accessing camera:", err);
      }
    }

    startCamera();

    const interval = setInterval(() => {
      if (isActive && videoRef.current && canvasRef.current) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) {
          ctx.drawImage(videoRef.current, 0, 0, 320, 180);
          const base64 = canvasRef.current.toDataURL('image/jpeg', 0.5).split(',')[1];
          onFrame(base64);
        }
      }
    }, 10000); // Check facial stress every 10 seconds to save tokens

    return () => {
      clearInterval(interval);
      if (videoRef.current && videoRef.current.srcObject) {
        (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
      }
    };
  }, [isActive, onFrame]);

  return (
    <div className="fixed inset-0 z-0 bg-black">
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        muted 
        className="w-full h-full object-cover opacity-60 grayscale-[0.3]"
      />
      <canvas ref={canvasRef} width="320" height="180" className="hidden" />

      {/* HUD Elements */}
      <div className="absolute inset-0 pointer-events-none border-[20px] border-sky-500/10">
        <div className="scan-line" />

        {/* Corner Brackets */}
        <div className="absolute top-8 left-8 w-16 h-16 border-t-2 border-l-2 border-sky-400/50" />
        <div className="absolute top-8 right-8 w-16 h-16 border-t-2 border-r-2 border-sky-400/50" />
        <div className="absolute bottom-8 left-8 w-16 h-16 border-b-2 border-l-2 border-sky-400/50" />
        <div className="absolute bottom-8 right-8 w-16 h-16 border-b-2 border-r-2 border-sky-400/50" />

        {/* Center Reticle */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-64 h-64 hud-ring" />
      </div>
    </div>
  );
};

export default CameraHUD;

