import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Thought, AppState, UserStats } from './types';
import CameraHUD from './components/CameraHUD';
import MemoryVault from './components/MemoryVault';
import { analyzeThought, detectStressFromFrame } from './services/geminiService';
import { GoogleGenAI, Modality } from '@google/genai';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [thoughts, setThoughts] = useState<Thought[]>([]);
  const [stats, setStats] = useState<UserStats>({
    thoughtsOffloaded: 0,
    presenceTime: 0,
    anxietyEvents: 0
  });
  const [currentTranscription, setCurrentTranscription] = useState('');

  const recognitionRef = useRef<any>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  // Initialize Speech Recognition for triggers
  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = true;
      recognitionRef.current.interimResults = true;

      recognitionRef.current.onresult = (event: any) => {
        const transcript = Array.from(event.results)
          .map((result: any) => result[0].transcript)
          .join('')
          .toLowerCase();

        if (transcript.includes('remember this thought') && appState !== AppState.LISTENING) {
          triggerCapture();
        } else if (appState === AppState.LISTENING) {
          setCurrentTranscription(transcript);
        }
      };

      recognitionRef.current.start();
    }

    return () => {
      if (recognitionRef.current) recognitionRef.current.stop();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [appState]);

  const triggerCapture = () => {
    setAppState(AppState.LISTENING);
    setCurrentTranscription('Listening...');
    // In a real app, we'd wait for silence or a button press to finalize the capture
    setTimeout(() => finalizeCapture(), 5000); 
  };

  const finalizeCapture = async () => {
    if (currentTranscription === '' || currentTranscription === 'Listening...') {
      setAppState(AppState.IDLE);
      return;
    }

    setAppState(AppState.SAVING);
    try {
      const analysis = await analyzeThought(currentTranscription);
      const newThought: Thought = {
        id: Date.now().toString(),
        content: currentTranscription,
        timestamp: Date.now(),
        tags: [analysis.category],
        priority: analysis.priority
      };

      setThoughts(prev => [newThought, ...prev]);
      setStats(prev => ({ ...prev, thoughtsOffloaded: prev.thoughtsOffloaded + 1 }));
      setAppState(AppState.CONFIRMED);

      // Play voice confirmation (Presence Guide)
      playConfirmation();

      setTimeout(() => setAppState(AppState.IDLE), 3000);
    } catch (err) {
      console.error(err);
      setAppState(AppState.IDLE);
    }
  };

  const playConfirmation = () => {
    const msg = new SpeechSynthesisUtterance("Got it. You can stay present now.");
    msg.rate = 0.9;
    msg.pitch = 1.1;
    window.speechSynthesis.speak(msg);
  };

  const handleFrame = useCallback(async (base64: string) => {
    const result = await detectStressFromFrame(base64);
    if (result.isStressed) {
      setAppState(AppState.STRESSED);
      setStats(prev => ({ ...prev, anxietyEvents: prev.anxietyEvents + 1 }));
      // Optionally notify user: "You look overwhelmed. Want to offload a thought?"
      setTimeout(() => setAppState(prev => prev === AppState.STRESSED ? AppState.IDLE : prev), 5000);
    }
  }, []);

  return (
    <div className="relative h-screen w-screen overflow-hidden flex text-white select-none">
      <CameraHUD onFrame={handleFrame} isActive={appState === AppState.IDLE} />

      {/* Main HUD Overlays */}
      <div className="relative z-10 w-full h-full flex p-6 gap-6 pointer-events-none">

        {/* Left Side: Stats & Status */}
        <div className="flex flex-col gap-6 w-64">
          <div className="ar-glass p-4 rounded-xl border-l-4 border-l-sky-500">
            <h1 className="font-orbitron text-lg font-bold tracking-tighter text-sky-400">FOCUS AR</h1>
            <p className="text-[10px] text-sky-300/50 uppercase tracking-[0.2em] mt-1 font-semibold">ADHD Cognitive Support</p>
          </div>

          <div className="ar-glass p-4 rounded-xl space-y-4">
            <div className="flex justify-between items-center">
              <span className="text-[10px] text-slate-400">STATUS</span>
              <span className={`text-[10px] font-bold ${
                appState === AppState.STRESSED ? 'text-red-400 animate-pulse' : 
                appState === AppState.LISTENING ? 'text-green-400 animate-pulse' : 'text-sky-400'
              }`}>{appState}</span>
            </div>
            <div className="h-1 bg-slate-800 rounded-full overflow-hidden">
              <div className="h-full bg-sky-500/50 w-[70%]" />
            </div>

            <div className="grid grid-cols-2 gap-4 pt-2">
              <div className="text-center">
                <p className="text-xl font-orbitron text-sky-400">{stats.thoughtsOffloaded}</p>
                <p className="text-[8px] text-slate-500 uppercase">Offloaded</p>
              </div>
              <div className="text-center">
                <p className="text-xl font-orbitron text-sky-400">{stats.anxietyEvents}</p>
                <p className="text-[8px] text-slate-500 uppercase">Stress Ev.</p>
              </div>
            </div>
          </div>

          <div className="mt-auto ar-glass p-4 rounded-xl text-[10px] text-slate-400 italic">
            "Whisper 'Remember this thought' to clear your cognitive load instantly."
          </div>
        </div>

        {/* Center Area: Active Interaction */}
        <div className="flex-1 flex flex-col items-center justify-center">
          {appState === AppState.LISTENING && (
            <div className="ar-glass p-8 rounded-full border-2 border-green-500/50 flex flex-col items-center gap-4 animate-in zoom-in duration-300">
              <div className="w-16 h-16 rounded-full bg-green-500/20 flex items-center justify-center animate-pulse">
                <i className="fa-solid fa-microphone text-green-400 text-2xl"></i>
              </div>
              <p className="font-orbitron text-green-400 tracking-widest text-sm">CAPTURING THOUGHT...</p>
              <p className="text-slate-300 max-w-md text-center italic">"{currentTranscription}"</p>
            </div>
          )}

          {appState === AppState.SAVING && (
            <div className="ar-glass p-8 rounded-2xl flex flex-col items-center gap-4">
              <div className="w-12 h-12 border-2 border-sky-400 border-t-transparent rounded-full animate-spin"></div>
              <p className="font-orbitron text-sky-400 text-sm">INDEXING MEMORY...</p>
            </div>
          )}

          {appState === AppState.CONFIRMED && (
            <div className="ar-glass p-8 rounded-full border-2 border-sky-400/50 flex flex-col items-center gap-4 animate-in zoom-in duration-300">
              <div className="w-16 h-16 rounded-full bg-sky-500/20 flex items-center justify-center">
                <i className="fa-solid fa-check text-sky-400 text-2xl"></i>
              </div>
              <p className="font-orbitron text-sky-400 tracking-widest text-sm">THOUGHT SAVED</p>
              <p className="text-sky-300/70 text-xs">Stay present. I have this now.</p>
            </div>
          )}

          {appState === AppState.STRESSED && (
            <div className="ar-glass p-8 rounded-2xl border-2 border-red-500/50 flex flex-col items-center gap-4 animate-bounce">
              <div className="w-12 h-12 rounded-full bg-red-500/20 flex items-center justify-center">
                <i className="fa-solid fa-triangle-exclamation text-red-400 text-xl"></i>
              </div>
              <p className="font-orbitron text-red-400 tracking-widest text-sm uppercase">Cognitive Overload Detected</p>
              <p className="text-slate-300 text-center text-xs">Consider offloading current thoughts to stay present.</p>
            </div>
          )}
        </div>

        {/* Right Side: Memory Vault */}
        <MemoryVault thoughts={thoughts} onClear={() => setThoughts([])} />
      </div>

      {/* Manual Controls - Sticky Footer */}
      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-4 z-20 pointer-events-auto">
        <button 
          onClick={triggerCapture}
          className={`group relative flex items-center justify-center w-20 h-20 rounded-full transition-all duration-500 ${
            appState === AppState.LISTENING 
            ? 'bg-red-500 shadow-[0_0_30px_rgba(239,68,68,0.5)]' 
            : 'bg-sky-500 hover:bg-sky-400 shadow-[0_0_20px_rgba(14,165,233,0.3)]'
          }`}
        >
          <div className="absolute inset-0 rounded-full border-2 border-white/20 animate-ping opacity-20" />
          <i className={`fa-solid ${appState === AppState.LISTENING ? 'fa-stop' : 'fa-brain'} text-2xl text-white`}></i>
          <span className="absolute -top-8 left-1/2 -translate-x-1/2 bg-slate-900 px-3 py-1 rounded text-[10px] whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity">
            {appState === AppState.LISTENING ? 'STOP CAPTURING' : 'MANUAL OFFLOAD'}
          </span>
        </button>
      </div>
    </div>
  );
};

export default App;

