import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeThought = async (text: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze this fleeting thought from an ADHD user. Summarize it briefly and categorize it. 
    Thought: "${text}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          category: { type: Type.STRING },
          priority: { type: Type.STRING, enum: ['low', 'medium', 'high'] }
        },
        required: ['summary', 'category', 'priority']
      }
    }
  });

  return JSON.parse(response.text);
};

export const detectStressFromFrames = async (base64Images: string[]) => {
  try {
    const parts = base64Images.map(data => ({
      inlineData: {
        mimeType: 'image/jpeg',
        data: data
      }
    }));

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...parts,
        { text: `You are an AR behavioral assistant for ADHD patients. 
        Analyze this sequence of 3 frames taken 1 second apart. 
        Look for specific physiological and behavioral markers of cognitive overload or anxiety:
        1. Facial: Furrowed brow, jaw clenching, lip biting, dilated pupils (if visible), or rapid blinking.
        2. Postural: Slumping, leaning too close to screen, or rigid neck.
        3. Behavioral: Hand-to-face fidgeting, darting eyes, or expressions of frustration.

        Provide a detailed assessment of stress level (0-100) and a list of detected indicators.` }
      ],
      config: {
        thinkingConfig: { thinkingBudget: 4000 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            stressScore: { type: Type.NUMBER, description: "Scale 0-100" },
            isHighStress: { type: Type.BOOLEAN },
            indicators: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING },
                  severity: { type: Type.NUMBER },
                  description: { type: Type.STRING }
                },
                required: ['type', 'severity', 'description']
              }
            },
            recommendation: { type: Type.STRING }
          },
          required: ['stressScore', 'isHighStress', 'indicators']
        }
      }
    });
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Advanced stress detection failed", e);
    return { stressScore: 0, isHighStress: false, indicators: [], recommendation: "" };
  }
};

import React, { useEffect, useRef } from 'react';

interface CameraHUDProps {
  onFrames: (base64Array: string[]) => void;
  isActive: boolean;
}

const CameraHUD: React.FC<CameraHUDProps> = ({ onFrames, isActive }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    async function startCamera() {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: 640, height: 480 },
          audio: false 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
      } catch (err) {
        console.error("Error accessing camera:", err);
      }
    }

    startCamera();

    const captureBurst = async () => {
      if (!isActive || !videoRef.current || !canvasRef.current) return;

      const frames: string[] = [];
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;

      for (let i = 0; i < 3; i++) {
        ctx.drawImage(videoRef.current, 0, 0, 320, 240);
        const base64 = canvasRef.current.toDataURL('image/jpeg', 0.6).split(',')[1];
        frames.push(base64);
        if (i < 2) await new Promise(resolve => setTimeout(resolve, 800)); // 800ms between frames
      }

      onFrames(frames);
    };

    const interval = setInterval(() => {
      captureBurst();
    }, 15000); // Trigger a behavioral check every 15 seconds

    return () => {
      clearInterval(interval);
      if (videoRef.current && videoRef.current.srcObject) {
        (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
      }
    };
  }, [isActive, onFrames]);

  return (
    <div className="fixed inset-0 z-0 bg-black">
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        muted 
        className="w-full h-full object-cover opacity-50 grayscale-[0.6]"
      />
      <canvas ref={canvasRef} width="320" height="240" className="hidden" />

      {/* HUD Elements */}
      <div className="absolute inset-0 pointer-events-none">
        {/* Subtle scanning motion overlay */}
        <div className="absolute inset-0 bg-gradient-to-b from-transparent via-sky-500/5 to-transparent h-1/2 w-full animate-[scan_6s_linear_infinite]" />

        {/* AR Grid Overlay */}
        <div className="absolute inset-0 opacity-10" style={{ backgroundImage: 'radial-gradient(#38bdf8 1px, transparent 1px)', backgroundSize: '40px 40px' }} />

        {/* Corner Brackets */}
        <div className="absolute top-12 left-12 w-20 h-20 border-t-2 border-l-2 border-sky-400/30" />
        <div className="absolute top-12 right-12 w-20 h-20 border-t-2 border-r-2 border-sky-400/30" />
        <div className="absolute bottom-12 left-12 w-20 h-20 border-b-2 border-l-2 border-sky-400/30" />
        <div className="absolute bottom-12 right-12 w-20 h-20 border-b-2 border-r-2 border-sky-400/30" />

        {/* Center Targeting */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-96 h-96 hud-ring" />
      </div>
    </div>
  );
};

export default CameraHUD;

