  id: string;
  content: string;
  timestamp: number;
  tags: string[];
  priority: 'low' | 'medium' | 'high';
}

export enum AppState {
  IDLE = 'IDLE',
  LISTENING = 'LISTENING',
  SAVING = 'SAVING',
  CONFIRMED = 'CONFIRMED',
  STRESSED = 'STRESSED',
  GUIDING = 'GUIDING'
}

export interface PresenceExercise {
  title: string;
  instructions: string;
  duration: number; // seconds
  visualType: 'breathing' | 'grounding' | 'focus';
}

export interface StressIndicator {
  type: string;
  severity: number; // 0-100
  description: string;
}

export interface UserStats {
  thoughtsOffloaded: number;
  presenceTime: number; // in minutes
  anxietyEvents: number;
  averageStressScore: number;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeThought = async (text: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze this fleeting thought from an ADHD user. Summarize it briefly and categorize it. 
    Thought: "${text}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          category: { type: Type.STRING },
          priority: { type: Type.STRING, enum: ['low', 'medium', 'high'] }
        },
        required: ['summary', 'category', 'priority']
      }
    }
  });

  return JSON.parse(response.text);
};

export const detectStressFromFrames = async (base64Images: string[]) => {
  try {
    const parts = base64Images.map(data => ({
      inlineData: {
        mimeType: 'image/jpeg',
        data: data
      }
    }));

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...parts,
        { text: `You are an AR behavioral assistant for ADHD patients. 
        Analyze this sequence of 3 frames. 
        1. Identify stress/overload markers.
        2. Detect "interruption habits" (sudden jerky movements, hand-to-mouth, looking away frequently).
        3. Recommend a specific Presence Exercise (Breathing, Grounding, or Focus Anchor) to help the user re-center.

        Provide a detailed assessment and the exercise.` }
      ],
      config: {
        thinkingConfig: { thinkingBudget: 4000 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            stressScore: { type: Type.NUMBER },
            isHighStress: { type: Type.BOOLEAN },
            habitDetected: { type: Type.STRING },
            indicators: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING },
                  severity: { type: Type.NUMBER },
                  description: { type: Type.STRING }
                },
                required: ['type', 'severity', 'description']
              }
            },
            presenceExercise: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                instructions: { type: Type.STRING },
                duration: { type: Type.NUMBER },
                visualType: { type: Type.STRING, enum: ['breathing', 'grounding', 'focus'] }
              },
              required: ['title', 'instructions', 'duration', 'visualType']
            }
          },
          required: ['stressScore', 'isHighStress', 'indicators', 'presenceExercise']
        }
      }
    });
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Advanced stress detection failed", e);
    return null;
  }
};

import React, { useEffect, useState } from 'react';
import { PresenceExercise } from '../types';

interface PresenceGuideProps {
  exercise: PresenceExercise;
  onComplete: () => void;
}

const PresenceGuide: React.FC<PresenceGuideProps> = ({ exercise, onComplete }) => {
  const [timeLeft, setTimeLeft] = useState(exercise.duration);

  useEffect(() => {
    if (timeLeft <= 0) {
      onComplete();
      return;
    }
    const timer = setTimeout(() => setTimeLeft(prev => prev - 1), 1000);
    return () => clearTimeout(timer);
  }, [timeLeft, onComplete]);

  return (
    <div className="flex flex-col items-center gap-8 animate-in fade-in zoom-in duration-700">
      <div className="relative flex items-center justify-center">
        {/* Visual Focus Element */}
        {exercise.visualType === 'breathing' && (
          <div className="relative w-48 h-48 flex items-center justify-center">
            <div className="absolute inset-0 border-4 border-sky-400/30 rounded-full animate-[ping_4s_ease-in-out_infinite]" />
            <div className="w-32 h-32 bg-sky-500/10 border-2 border-sky-400/50 rounded-full flex items-center justify-center transition-all duration-[4000ms] animate-[pulse_4s_ease-in-out_infinite]">
              <div className="text-sky-300 font-orbitron text-xs font-bold">BREATHE</div>
            </div>
          </div>
        )}

        {exercise.visualType === 'focus' && (
          <div className="relative w-48 h-48 flex items-center justify-center">
            <div className="w-4 h-4 bg-sky-400 rounded-full shadow-[0_0_20px_#38bdf8] animate-pulse" />
            <div className="absolute w-24 h-24 border border-sky-400/20 rounded-full border-dashed animate-[spin_10s_linear_infinite]" />
          </div>
        )}

        {exercise.visualType === 'grounding' && (
          <div className="relative w-48 h-48 grid grid-cols-2 gap-2 opacity-60">
            {[1, 2, 3, 4].map(i => (
              <div key={i} className="border border-sky-400/40 rounded bg-sky-400/5 animate-pulse" style={{ animationDelay: `${i * 200}ms` }} />
            ))}
