        )}
      </div>

      <div className="ar-glass p-8 rounded-3xl max-w-md text-center border-t-4 border-t-sky-400">
        <h2 className="font-orbitron text-sky-400 tracking-[0.3em] text-lg mb-2">{exercise.title.toUpperCase()}</h2>
