              className="h-full bg-sky-400 transition-all duration-1000" 
              style={{ width: `${(timeLeft / exercise.duration) * 100}%` }} 
            />
          </div>
          <span className="font-orbitron text-[10px] text-sky-400 w-8">{timeLeft}s</span>
        </div>
      </div>
    </div>
  );
};

