/**
 * Haptic patterns for the AR HUD
 */
export const HapticPatterns = {
  CLICK: 10,
  UPLINK_START: 50,
  SUCCESS: [40, 60, 40],
  STRESS_ALERT: [100, 100, 100, 100],
  BREATH_IN: 200,
  BREATH_OUT: 100,
  ERROR: [50, 50, 50, 50, 50]
};

export const triggerHaptic = (pattern: number | number[]) => {
  if ('vibrate' in navigator) {
    try {
      navigator.vibrate(pattern);
    } catch (e) {
      console.debug('Haptic feedback not supported on this device/browser interaction.');
    }
  }
};

