      lastGuideTimeRef.current = now;
      setStats(prev => ({ 
        ...prev, 
        anxietyEvents: prev.anxietyEvents + 1,
        averageStressScore: Math.round((prev.averageStressScore + result.stressScore) / 2)
      }));
      playVoiceConfirmation("Breath with me for a moment.");
