          </div>

          {/* Biometric Stress Meter */}
          <div className="ar-glass p-5 rounded-2xl space-y-4">
            <div className="flex justify-between items-center">
              <span className="text-[11px] text-slate-400 font-orbitron">COGNITIVE LOAD</span>
