                <div key={i} className="flex items-start gap-2 text-[9px] animate-in fade-in slide-in-from-left duration-500">
                  <div className={`mt-1.5 w-1.5 h-1.5 rounded-full ${ind.severity > 50 ? 'bg-red-400' : 'bg-sky-400'}`} />
