import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeThought = async (text: string) => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Analyze this fleeting thought from an ADHD user. Summarize it briefly and categorize it. 
    Thought: "${text}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          category: { type: Type.STRING },
          priority: { type: Type.STRING, enum: ['low', 'medium', 'high'] }
        },
        required: ['summary', 'category', 'priority']
      }
    }
  });

  return JSON.parse(response.text);
};

export const detectStressFromFrames = async (base64Images: string[]) => {
  try {
    const parts = base64Images.map(data => ({
      inlineData: {
        mimeType: 'image/jpeg',
        data: data
      }
    }));

    // Using gemini-3-pro-preview for highly accurate behavioral analysis
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        ...parts,
        { text: `You are an expert neuro-behavioral AR assistant specialized in ADHD. 
        Analyze this sequence of 5 images captured 500ms apart to identify granular stress markers and cognitive overload signatures.

        Focus on:
        1. Ocular Patterns: Saccadic movements, blink rate frequency, pupil dilation, or fixed-staring (zoning out).
        2. Micro-Expressions: Nasolabial tension, lip compression, or forehead furrowing.
        3. Kinesthetic Habits: Hand-to-face contact, repetitive neck movements, or postural rigidity.
        4. Interruption Signals: Sudden gaze shifts or involuntary facial tics suggesting a distracting thought.

        Provide a quantitative stress score and detailed behavioral markers.` }
      ],
      config: {
        thinkingConfig: { thinkingBudget: 16000 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            stressScore: { type: Type.NUMBER, description: "Composite score from 0-100" },
            isHighStress: { type: Type.BOOLEAN },
            behavioralMarkers: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  intensity: { type: Type.NUMBER, description: "1-10" },
                  description: { type: Type.STRING }
                },
                required: ['name', 'intensity', 'description']
              }
            },
            indicators: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING },
                  severity: { type: Type.NUMBER },
                  description: { type: Type.STRING }
                },
                required: ['type', 'severity', 'description']
              }
            },
            presenceExercise: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                instructions: { type: Type.STRING },
                duration: { type: Type.NUMBER },
                visualType: { type: Type.STRING, enum: ['breathing', 'grounding', 'focus'] }
              },
              required: ['title', 'instructions', 'duration', 'visualType']
            }
          },
          required: ['stressScore', 'isHighStress', 'behavioralMarkers', 'indicators', 'presenceExercise']
        }
      }
    });
    return JSON.parse(response.text);
  } catch (e) {
    console.error("Granular stress detection failed", e);
    return null;
  }
};

import React, { useEffect, useRef } from 'react';

interface CameraHUDProps {
  onFrames: (base64Array: string[]) => void;
  isActive: boolean;
}

const CameraHUD: React.FC<CameraHUDProps> = ({ onFrames, isActive }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    async function startCamera() {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: 640, height: 480 },
          audio: false 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
      } catch (err) {
        console.error("Error accessing camera:", err);
      }
    }

    startCamera();

    const captureBurst = async () => {
      if (!isActive || !videoRef.current || !canvasRef.current) return;

      const frames: string[] = [];
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;

      // Captured 5 frames for high-granularity temporal analysis
      for (let i = 0; i < 5; i++) {
        ctx.drawImage(videoRef.current, 0, 0, 320, 240);
        const base64 = canvasRef.current.toDataURL('image/jpeg', 0.5).split(',')[1];
        frames.push(base64);
        if (i < 4) await new Promise(resolve => setTimeout(resolve, 500)); // 500ms interval
      }

      onFrames(frames);
    };

    const interval = setInterval(() => {
      captureBurst();
    }, 12000); // Trigger a behavioral check every 12 seconds

    return () => {
      clearInterval(interval);
      if (videoRef.current && videoRef.current.srcObject) {
        (videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop());
      }
    };
  }, [isActive, onFrames]);

  return (
    <div className="fixed inset-0 z-0 bg-black overflow-hidden">
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        muted 
        className="w-full h-full object-cover opacity-50 grayscale-[0.6]"
      />
      <canvas ref={canvasRef} width="320" height="240" className="hidden" />

      {/* HUD Elements */}
      <div className="absolute inset-0 pointer-events-none">
        {/* Subtle scanning motion overlay */}
        <div className="scan-line" />

        {/* AR Grid Overlay */}
        <div className="absolute inset-0 opacity-[0.05]" style={{ backgroundImage: 'radial-gradient(#38bdf8 1.5px, transparent 1.5px)', backgroundSize: '60px 60px' }} />

        {/* Animated Corner Brackets */}
        <div className="absolute top-12 left-12 w-24 h-24 border-t-2 border-l-2 border-sky-400/30 bracket-shimmer" />
        <div className="absolute top-12 right-12 w-24 h-24 border-t-2 border-r-2 border-sky-400/30 bracket-shimmer" style={{ animationDelay: '1s' }} />
        <div className="absolute bottom-12 left-12 w-24 h-24 border-b-2 border-l-2 border-sky-400/30 bracket-shimmer" style={{ animationDelay: '2s' }} />
        <div className="absolute bottom-12 right-12 w-24 h-24 border-b-2 border-r-2 border-sky-400/30 bracket-shimmer" style={{ animationDelay: '3s' }} />

        {/* Center Targeting with Pulse */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[500px] h-[500px] hud-ring flicker" />
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-4 h-4 flex items-center justify-center">
            <div className="w-1 h-1 bg-sky-400/50 rounded-full" />
            <div className="absolute w-12 h-0.5 bg-sky-400/20" />
            <div className="absolute h-12 w-0.5 bg-sky-400/20" />
        </div>

        {/* Decorative HUD Details */}
        <div className="absolute top-1/2 left-24 -translate-y-1/2 flex flex-col gap-2 opacity-40">
            <div className="w-1 h-8 bg-sky-500/20" />
            <div className="w-1 h-2 bg-sky-500/40" />
            <div className="w-1 h-12 bg-sky-500/10" />
        </div>
        <div className="absolute top-1/2 right-24 -translate-y-1/2 flex flex-col gap-2 opacity-40 items-end">
            <div className="w-1 h-12 bg-sky-500/10" />
            <div className="w-1 h-2 bg-sky-500/40" />
            <div className="w-1 h-8 bg-sky-500/20" />
        </div>

        {/* Subtle floating telemetry labels */}
        <div className="absolute bottom-24 left-1/2 -translate-x-1/2 font-orbitron text-[8px] text-sky-400/30 tracking-[1em] uppercase">
            Neural Feed Synchronized
        </div>
      </div>
    </div>
  );
};

